#!/usr/bin/env bash
# =============================================================================
# download-reference-dataset.sh
#
# Downloads the USGS public-domain SEG-Y reference dataset (~1.71 GB) for
# full-scale benchmarking of AI-Compress-Seismic-v1.
#
# IMPORTANT: This script is OPTIONAL and NOT run during the standard CI build.
#            The CI pipeline uses only the synthetic fixtures generated by
#            SegyFixtureGenerator (which run in < 2 minutes with no downloads).
#
# Run this script locally before executing sdc-bench or full-scale testing:
#   chmod +x download-reference-dataset.sh
#   ./download-reference-dataset.sh
#
# The dataset will be placed in:
#   sdc-fixtures/src/test/resources/fixtures/reference/
#
# Requirements:
#   - curl or wget (auto-detected)
#   - ~3.5 GB of free disk space (compressed download + extracted SEG-Y)
#   - Internet access to USGS ScienceBase or NGDC archive
# =============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FIXTURES_DIR="${SCRIPT_DIR}/src/test/resources/fixtures/reference"

mkdir -p "${FIXTURES_DIR}"

echo "=== SDC Reference Dataset Downloader ==="
echo "Target directory: ${FIXTURES_DIR}"
echo ""

# -----------------------------------------------------------------------------
# Dataset: USGS ScienceBase — Alaska seismic reflection data (public domain)
#
# The USGS National Geophysical Data Center (NGDC) and ScienceBase provide
# SEG-Y reflection seismic datasets in the public domain. Below are two
# candidate sources commonly used as reference datasets in seismic processing
# research. At least one should be available at any given time.
#
# OPTION 1: USGS ScienceBase — Alaska Regional Profiles
#   URL: https://www.sciencebase.gov/catalog/item/5e1a6f07e4b0ecf25123af8b
#   Approximate size: 1.71 GB (primary target referenced in the PRD)
#   Format: SEG-Y Rev1, format code 5 (IEEE float32)
#
# OPTION 2: USGS NGDC Open-File Report seismic data
#   URL: https://www.ngdc.noaa.gov/seismicsurveys/
#   Navigate to a publicly accessible SEG-Y survey of similar size.
#
# OPTION 3: OpendTect/dGB open datasets (Apache 2.0 license)
#   URL: https://terranubis.com/datainfo/F3-Demo-2020
#   The F3 Netherlands Open Seismic Dataset is ~1.5 GB and commonly used for
#   seismic processing benchmarks.
#   Direct download (if available):
#   https://drive.google.com/uc?export=download&id=<ID>
#
# -----------------------------------------------------------------------------
# INSTRUCTIONS:
#
# 1. Visit the USGS ScienceBase URL above and download the SEG-Y file(s)
#    manually if direct download is unavailable from CI/automated scripts.
#
# 2. Place the downloaded .segy / .sgy file(s) in:
#      ${FIXTURES_DIR}/
#
# 3. Verify the checksums match the values in:
#      ${SCRIPT_DIR}/src/test/resources/fixtures/checksums.sha256
#    (Note: the reference dataset checksums are separate from the synthetic
#     fixture checksums generated by SegyFixtureGenerator.)
#
# 4. To run the full benchmark with the reference dataset:
#      mvn verify -pl sdc-bench -Dsdc.bench.dataset=${FIXTURES_DIR}/reference.segy
# -----------------------------------------------------------------------------

# Detect download tool
if command -v curl &>/dev/null; then
    DOWNLOADER="curl"
elif command -v wget &>/dev/null; then
    DOWNLOADER="wget"
else
    echo "ERROR: Neither curl nor wget found. Install one and retry."
    exit 1
fi

echo "Download tool: ${DOWNLOADER}"
echo ""
echo "NOTE: The USGS ScienceBase dataset requires accepting a terms-of-use agreement."
echo "      Automated download may not be possible from all networks."
echo ""

# Placeholder URL — replace with the actual direct download link obtained from
# the USGS ScienceBase item page after accepting the data use agreement.
USGS_SEGY_URL="${SDC_REFERENCE_DATASET_URL:-}"

if [[ -z "${USGS_SEGY_URL}" ]]; then
    echo "=== Manual download required ==="
    echo ""
    echo "Set SDC_REFERENCE_DATASET_URL to the direct download URL, or download manually:"
    echo ""
    echo "  1. Visit: https://www.sciencebase.gov/catalog/item/5e1a6f07e4b0ecf25123af8b"
    echo "  2. Download the SEG-Y file (~1.71 GB)"
    echo "  3. Copy it to: ${FIXTURES_DIR}/"
    echo ""
    echo "Alternative (OpendTect F3 dataset, ~1.5 GB):"
    echo "  1. Visit: https://terranubis.com/datainfo/F3-Demo-2020"
    echo "  2. Follow the download instructions for SEG-Y format"
    echo "  3. Copy it to: ${FIXTURES_DIR}/"
    echo ""
    echo "After placing the file, compute and record its SHA-256:"
    echo "  sha256sum ${FIXTURES_DIR}/*.segy >> ${SCRIPT_DIR}/src/test/resources/fixtures/checksums.sha256"
    echo ""
    echo "Then run the full benchmark:"
    echo "  mvn verify -pl sdc-bench -Dsdc.bench.dataset=\$(ls ${FIXTURES_DIR}/*.segy | head -1)"
    echo ""
    exit 0
fi

# Automated download (only if URL provided via environment variable)
OUTPUT_FILE="${FIXTURES_DIR}/reference.segy"

echo "Downloading reference dataset to: ${OUTPUT_FILE}"
echo "URL: ${USGS_SEGY_URL}"
echo ""

if [[ "${DOWNLOADER}" == "curl" ]]; then
    curl --location --progress-bar --retry 3 --retry-delay 5 \
         --output "${OUTPUT_FILE}" \
         "${USGS_SEGY_URL}"
else
    wget --progress=bar:force --tries=3 --wait=5 \
         --output-document="${OUTPUT_FILE}" \
         "${USGS_SEGY_URL}"
fi

echo ""
echo "Download complete: ${OUTPUT_FILE}"
echo "File size: $(du -sh "${OUTPUT_FILE}" | cut -f1)"
echo ""

# Compute and display SHA-256
echo "SHA-256 checksum:"
sha256sum "${OUTPUT_FILE}"
echo ""
echo "=== Done. Reference dataset ready for benchmarking. ==="
echo ""
echo "Run the full benchmark:"
echo "  mvn verify -pl sdc-bench -Dsdc.bench.dataset=${OUTPUT_FILE}"
